/// <reference path="../typings/index.d.ts" />
import jibo = require('jibo');

class PhotoStyler {
  public static log = null;

  constructor() {

  }

  /*From Photoshop:
  • Brightness: +60
  • Contrast: +70
  • Vibrance: +50
  • Saturation: +5
  • Color Balance:
      Cyan/Red: -3
      Magenta/Green: 0
      Yellow/Blue: +5

  •  The image was also sharpened using Smart Sharpened in photoshop. (I've attached the saved preset of this.)
  Amount: 340%
  Radius: 0.9px
  Reduce Noise: 25%
  */

  /*Previous setting for glfx
  .unsharpMask(50, 0.17)//radius, strength
  .brightnessContrast(0.1 ,0.2)//brightness, contrast -1 to 1
  .vibrance(0.2)//-1 to 1
  .hueSaturation(0, 0.05)//hue, saturation -1 to 1
  .curves([
  [0.1, 0], [0.5, 0.49], [1, 1]], //red curve
  [[0.1, 0], [1, 1]], //green  curve
  [[0.1, 0], [0.5, 0.51], [1, 1]]) //blue curve
  */

  style(urls:Array<any>, callback:Function){
    let loadTasks:Array<any> = [];
    for(let i = 0; i < urls.length; i++){
      loadTasks.push({
        id:`photo${i}`,
        src: urls[i].url,
        format:'image'
      });
    }
    jibo.loader.load(loadTasks, (err, result)=>{
      if(err){
        callback(err);
        return;
      }

      // TODO :: Not this! We want to not have to redraw to canvas when single photo
      let canvas = document.createElement('canvas');
      canvas.width = 1280;
      canvas.height = 720;
      let ctx = canvas.getContext('2d');
      if(urls.length == 4){
        ctx.drawImage(result.photo0, 0, 0, 640, 360);
        ctx.drawImage(result.photo1, 640, 0, 640, 360);
        ctx.drawImage(result.photo2, 0, 360, 640, 360);
        ctx.drawImage(result.photo3, 640, 360, 640, 360);
        callback(null, canvas.toDataURL('image/jpeg', 0.9));
      }
      else{
        ctx.drawImage(result.photo0, 0, 0, 1280, 720);
        callback(null, canvas.toDataURL('image/jpeg', 0.9));
      }
    });
  }

  destroy(){
    //just in case we have something to cleanup
  }

}
module.exports = PhotoStyler;
