/// <reference path="../typings/index.d.ts" />
import jibo = require('jibo');
import FaceScore from './FaceScore';
import {BeSkill} from '@be/be-framework';
const GoalFinishedStatus = jibo.action.types.GoalFinishedStatus;
require('./FaceScore');

class FaceSearcher {

    public static log = null;

    // best score, derived from motion data
    private _bestScore:FaceScore;
    private _minScore:FaceScore;  // minimum score require for a 'success'
    private _nextScore:FaceScore;  // minimum score require for a 'success'
    private _searchTimer:any;
    private _searchLevel:number;

    private _callback:Function;

    private DEFAULT_DURATION:number = 6000;

    public set minScore(score:FaceScore) {
        this._minScore = score;
        // make sure heuristic has been generated
        this._minScore.generateHeuristic();
    }

    public get bestScore():FaceScore {
        return this._bestScore;
    }

    constructor() {
        // bind method called by lps
        this.onMotion = this.onMotion.bind(this);
        this._nextScore = new FaceScore();
    }

    public reset():void {
        this._callback = null;
        this._minScore = null;
        this._bestScore = null;
        clearTimeout(this._searchTimer);
        this._searchTimer = null;
        jibo.lps.events.motion.removeListener(this.onMotion);
    }

    /////////////////// FACE FIND APPROACHES ///////////////////

    /**
     * Start searching for faces from the lps motion data stream.
     * jibo.expression.AttentionMode.ATTRACTABLE or jibo.expression.AttentionMode.ENGAGED
     * @memberOf InitialSearcher
     */
    public async search(done?:Function, minScore?:FaceScore, duration:number = 0):Promise<void> {
        // reset
        this.reset();

        // setup
        this._callback = done;
        this._minScore = minScore;
        // make sure minScore has generated its heuristic
        if(this._minScore){
            this._minScore.generateHeuristic();
        }

        // set initial minimum
        if(duration > 0){
            this.setupTimer(duration);
        }

        // create an empty best score
        this._bestScore = new FaceScore();

        // listen for change in lps
        jibo.lps.events.motion.on(this.onMotion);
    }

    public stopSearch(clearCallback:boolean = true) {
        if(clearCallback){
            this._callback = null;
        }
        this.searchComplete(false);
    }

    public checkAgainstBest(minScore:FaceScore):boolean {
        if(minScore){
            // make sure minScore has generated its heuristic before comparing
            minScore.generateHeuristic();
            if(this._bestScore && minScore){
                return minScore.checkForEqualBetter(this._bestScore);
            }
        }
        return false;
    }

    // called each time the motion data from the lps changes
    private onMotion(data:any):void {
        // convert curent lps data into a FaceScore
        this._nextScore.createScore(jibo.lps.motionData);
        if(this._bestScore.checkForEqualBetter(this._nextScore)) {
            this._bestScore.applyScore(this._nextScore);
            this.checkAgainstMin();
        }
    }

    private checkAgainstMin():void {
        // make sure minScore has generated its heuristic before comparing
        if(this._minScore && this._minScore.checkForEqualBetter(this._bestScore)){
            this.searchComplete(true, false);
        }
    }

    private searchComplete(found:boolean, stopSearch:boolean = true):void {
        FaceSearcher.log.debug('searchComplete() with result: ' + found + ', will stop search:' + stopSearch);
        // stop timer
        clearTimeout(this._searchTimer);
        this._searchTimer = null;
        // stop search update
        if(stopSearch){
            jibo.lps.events.motion.removeListener(this.onMotion);
        }
        // return results
        if(this._callback) {
            this._callback(found);
            this._callback = null;
        }
    }

    private setupTimer(duration:number):void {
        this._searchTimer = setTimeout(
            () => {
                FaceSearcher.log.debug('timed out');
                this.searchComplete(false);
                return;
            },
            duration
        );
    }
}

export default FaceSearcher;
