/// <reference path="../typings/index.d.ts" />
import {BeSkill, Options} from '@be/be-framework';
import jibo = require('jibo');
import PhotoView from './views/PhotoView';
import FlashView from './views/FlashView';
import CameraView from './views/CameraView';
import Analytics from './Analytics';
import FrameHelper from './FrameHelper';
import FaceSearcher from './FaceSearcher';

const PhotoStyler = require('./PhotoStyler');
const FaceFinder = require('./FaceFinder');

const mainFlow: any = require('./flows/create-main');

class Create extends BeSkill {

    //for unit tests:
    public static PhotoStyler = PhotoStyler;
    public static FrameHelper = FrameHelper;
    public flow: any;
    private _tracker:Analytics = null;
    private _assetTokens:any[];
    private _pmHandle: jibo.expression.AttentionHandle;

    /**
     * Create skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?: Options) {
        super(assetPack);
        this.flow = null;
        FaceSearcher.log = this.log.createChild('FaceSearcher');
        FrameHelper.log = this.log.createChild('FrameHelper');
        PhotoStyler.log = this.log.createChild('PhotoStyler');
        FaceFinder.log = this.log.createChild('FaceFinder');
        CameraView.log = this.log.createChild('CameraView');
        FlashView.log = this.log.createChild('FlashView');
        PhotoView.log = this.log.createChild('PhotoView');
    }

    preload(done: (err?: any)=>void): void {
        const load = jibo.loader.load({
            src: 'audio/Shutter_01.m4a',
            cache: jibo.loader.activeCache
        }, done);
        this._assetTokens = load.tokens;
    }

    /**
     * Start the skill
     * @method open
     */
    open(result?: any, refresh?: boolean): void {
        if (refresh) {
            this.cleanup(this.open.bind(this, result));
        }
        else {
            //because we expect users to back away from the robot to use the camera, always re-enable listening and movement during menus
            jibo.mim.silentMenus = false;
            jibo.face.views.disableMovement = false;
            // register view classes, OK if they are already registered
            jibo.face.views.creator.registerClass(PhotoView);
            jibo.face.views.creator.registerClass(FlashView);
            jibo.face.views.creator.registerClass(CameraView);

            // determine intent
            let intent = 'menu';
            if (result && result.nlu && result.nlu.intent) {
                intent = result.nlu.intent;
            }

            // instantiate tracker, if tracker is not null then we are refreshing skill
            if(!this._tracker){
                this._tracker = new Analytics(this);
            }
            this._tracker.reset((intent === 'createSomePhotos'));

            // setup and start main flow
            const options = {
                assetPack: this.assetPack,
                params: {intent: intent},
                blackboard: {
                    photoStyler: new PhotoStyler(this.log),
                    faceFinder: new FaceFinder(this.log),
                    lightRing: this.setLightRing,
                    headRatio: .56,
                    log: this.log,
                    tracker:this._tracker,
                    skill:this
                },
                enableLogging: true
            };
            this.flow = jibo.flow.run(
                mainFlow,
                options,
                (err, status) => {
                    // clean up classes within flow

                    // if not interrupted clean up flow, otherwise exit will get called by interruption
                    if (status !== jibo.bt.Status.INTERRUPTED) {
                        this.log.info('flow ended without interruption, destroy flow & calling exit');
                        this.destroyFlow();
                        this.exit();
                    }
                    else{
                        this.log.info('flow ended with interruption, not calling exit');
                    }
                }
            );
        }
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done: () => void): void {
        // unload sounds
        jibo.loader.unload(this._assetTokens);
        this._assetTokens = null;
        // unregister view classes
        jibo.face.views.creator.unregisterClass('PhotoView');
        jibo.face.views.creator.unregisterClass('FlashView');
        jibo.face.views.creator.unregisterClass('CameraView');
        // cleanup
        this.cleanup(done);
    }

    public async setMode(mode: jibo.expression.AttentionMode): Promise<jibo.expression.AttentionHandle> {
        this._pmHandle = await jibo.expression.pushAttentionMode(mode);
        return this._pmHandle;
    }

    public async releaseMode(): Promise<void> {
        if (this._pmHandle) {
            await this._pmHandle.release();
            this._pmHandle = null;
        }
    }

    public setLightRing(turnOn:boolean):void{
        if(turnOn){
            jibo.embodied.listen.enterActiveMode(jibo.embodied.listen.ActiveListenMode.UI);
        }else{
            jibo.embodied.listen.exitActiveMode();
        }
    }

    private destroyFlow() {
        if(this.flow) {
          this.log.info('flow ended, destroy flow any classes on blackboard');
          if(this.flow.blackboard) {
              if(this.flow.blackboard.faceFinder) {
                  this.flow.blackboard.faceFinder.destroy();
              }
              if(this.flow.blackboard.photoStyler) {
                  this.flow.blackboard.photoStyler.destroy();
              }
          }
          this.flow.destroy();
          this.flow = null;
        }
    }

    private cleanup(done: () => void): void{
      // turn off light ring, just in case it got left on
      this.setLightRing(false);
      // if flow, close & destroy, also disable viewfinder & clean views
      if (this.flow) {
          Promise.all([
              //stop & destroy the main flow
              this.flow.stop()
              .catch((err) => {
                  this.log.debug('Error when stopping flow: ', err);
              })
              .then(() => {
                  this.destroyFlow();
              }),

              // release any attention mode handles
              this.releaseMode(),

              // disable viewfinder (in case we were interrupted while it was open)
              this.disableViewFinder()
              .catch((err) => {
                  this.log.debug('cleanup() setViewfinder disable error: ', err);
              }),

              //clean up views
              this.cleanupViews()
              .catch((err) => {
                  this.log.debug('Eror when closing views: ', err);
              })
          ])
          .then(() => {
              done();
          });
      } else {
          Promise.all([
              // release any attention mode handles
              this.releaseMode(),

              // disable viewfinder (in case we were interrupted while it was open)
              this.disableViewFinder()
              .catch((err) => {
                  this.log.debug('cleanup() setViewfinder disable error: ', err);
              }),

              //clean up views
              this.cleanupViews()
              .catch((err) => {
                  this.log.debug('Eror when closing views: ', err);
              })
          ])
          .then(() => {
              done();
          });
      }
    }

    /**
     * Make sure view finder is disabled.
     */
    private disableViewFinder(): Promise<void> {
        return new Promise<void>((resolve) => {
            jibo.media.setViewfinder(
                {enable: false},
                (error)=> {
                    if (error) {
                        this.log.error('cleanup() setViewfinder disable error: ',error);
                    }
                    resolve();
                }
            );
        });
    }

    /**
     * Clean up views.
     * If a skill was chosen then views should already be closed and current view empty,
     * if currentView is not empty there was a problem and we close views
     */
    private cleanupViews(): Promise<void> {
        return new Promise<void>((resolve) => {
            jibo.face.views.viewStackCleanup()
            .then(()=> {
                resolve();
            })
            .catch(()=> {
                this.log.debug('cleanupViews() failed to remove all views, calling done anyway');
                resolve();
            });
        });
    }
}

module.exports = Create;
