import {BeSkill} from '@be/be-framework';

// analytics class for Create skill
export default class Analytics {
    private skill:BeSkill;
    private _isPhotobooth:boolean = false;
    private _retries:number = 0;
    private _howFound:string;

    constructor(skill:BeSkill, ) {
        this.skill = skill;
    }

    public reset(isPhotobooth:boolean) {
        this._isPhotobooth = isPhotobooth;
        this._retries = 0;
        this._howFound = 'none_found';
    }

    public set found(howFound:'check'|'attractable'|'none_found') {
        this._howFound = howFound;
    }

    public retry():void {
        this._retries++;
        this._howFound = 'none_found';
    }

    public photoSaved(saved:boolean = true) {
        let eventName:string = (this._isPhotobooth) ? 'Photobooth captured' : 'Photo captured';
        this.skill.track(
            eventName,
            {
                photo_saved:saved,
                photo_retries:this._retries,
                how_found_user:this._howFound
            }
        );
    }
}
