/// <reference path="../../typings/index.d.ts" />
import jibo = require('jibo');

/**
* View class created to test use of custom transitions
* @class PhotoView
* @extends module:jibo/face.View
*/
class PhotoView extends jibo.rendering.gui.views.View
{
    public static log = null;
    /**
    * The default class identifier.
    * Generally used to register the class.
    * @name module:jibo/face.TransMenu#DEFAULT_TYPE
    * @type {String}
    * @private
    * @readOnly
    */
    public static get DEFAULT_TYPE():string {return 'PhotoView';}

    private _photoClip:jibo.rendering.gui.components.Clip;
    private _choiceBtn:jibo.rendering.gui.components.MenuButton;

    /**
    * The Class type variant.
    * The MenuButton allows for type variants within it.
    * @overrides
    * @name module:jibo/face.TransMenu#_type
    * @type {String}
    * @protectedjibo sim /
    */
    protected _type:string = PhotoView.DEFAULT_TYPE;

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Construct View
     */
    constructor () {
        super();
        // have custom eye transitions happen in all cases of transition to or from EyeView
        this.id = 'photoView';
        this.transitionStageOnly = true;
        this.closeOnSwipeDown = false;
        (<any>this)._category = jibo.face.views.CATEGORY_DISPLAY;
    }

    public applyData():void {
        // load sfx
        this.addAssetDescriptorObject(
            {
                id: 'save-sfx',
                type: 'sound',
                src: 'audio/save.m4a'
            }
        );
        this.addAssetDescriptorObject(
            {
                id: 'delete-sfx',
                type: 'sound',
                src: 'audio/delete.m4a'
            }
        );
        // add clip for save or delete icon to be used atop photo
        this._choiceBtn = new jibo.rendering.gui.components.MenuButton();
        this._choiceBtn.addAssetDescriptorObject(
            {
                id: 'ok',
                type: 'texture',
                src: 'core://resources/actionIcons/ok.png',
                cache: 'global-gui'//jibo.rendering.gui.ViewManager.GLOBAL_CACHE
            }
        );
        this._choiceBtn.addAssetDescriptorObject(
            {
                id: 'delete',
                type: 'texture',
                src: 'core://resources/actionIcons/delete.png',
                cache: 'global-gui'//jibo.rendering.gui.ViewManager.GLOBAL_CACHE
            }
        );

        this._choiceBtn.interactable = false;
        this._choiceBtn.applyButtonType(jibo.rendering.gui.components.MenuButton.ACTION);

        this.addComponent(this._choiceBtn, 'choiceBtn');

        super.applyData();
    }

    public ready():void {
        // hide choice clip
        this._choiceBtn.display.visible = false;
        super.ready();
    }

    public addPhoto(photoSrc:any) {
        let image = new Image();
        image.src = photoSrc;//notepad.photoBase64;
        let bt = new PIXI.BaseTexture(image);
        let tex = new PIXI.Texture(bt);
        let sprite = new PIXI.Sprite(tex);

        if(!this._photoClip){
            jibo.rendering.gui.components.Clip.createFromDisplayObject(sprite);
            this.stage.addChildAt(sprite, 0);
        }
        else{
            this._photoClip.display.removeChildren();
            this._photoClip.display.addChild(sprite);
        }
    }

    public addPhotoToLoad(url:string) {
          this.addAssetDescriptorObject(
            {
                id: 'photoImage',
                type: 'texture',
                src: url
            }
          );
    }

    public displayPhoto() {
        let sprite = new PIXI.Sprite(this.assets['photoImage']);

        if(!this._photoClip){
            jibo.rendering.gui.components.Clip.createFromDisplayObject(sprite);
            this.stage.addChildAt(sprite, 0);
        }
        else{
            this._photoClip.display.removeChildren();
            this._photoClip.display.addChild(sprite);
        }
    }

    public showChoice(save:boolean, done?:Function):void{
        // show save or delete sprite
        let action:jibo.rendering.gui.actions.ActionData = new jibo.rendering.gui.actions.ActionData('sound', {id:''});
        if(save){
            // set color to green, icon to check
            this._choiceBtn.setIcon(new PIXI.Sprite(this.assets['ok']));
            this._choiceBtn.colors = 'confirm';
            action.data.id = 'save-sfx';
        }
        else {
            // set color to red, icon to trash
            this._choiceBtn.setIcon(new PIXI.Sprite(this.assets['delete']));
            this._choiceBtn.colors = 'cancel';
            action.data.id = 'delete-sfx';
        }
        let choiceDisplay:PIXI.Container = this._choiceBtn.display;
        let btnDisplay:PIXI.Container = this._choiceBtn.buttonDisplay;
        this._choiceBtn.setTargetPosition(
            jibo.face.width/2 - choiceDisplay.width/2,
            jibo.face.height/2 - choiceDisplay.height/2,
            true
        );
        choiceDisplay.visible = true;
        this.stage.setChildIndex(choiceDisplay, this.stage.children.length - 1);
        // play sound, have to unlock input, should allow override in actionHandler
        this._inputLocked = false;
        super.actionHandler(action);
        this._inputLocked = true;

        // start tween
        jibo.rendering.tween.TweenManager.play(
            btnDisplay,
            {
                to: {
                    'scale.x': 1,
                    'scale.y': 1
                },
                from: {
                    'scale.x': 0,
                    'scale.y': 0
                },
                duration: 750,
                ease: 'backOut'
            },
            () => {
                // done once reached apex
                if(done){
                    done();
                }
            }
        );
        // tween alpha
        jibo.rendering.tween.TweenManager.play(
            btnDisplay,
            {
                to: {alpha: 1},
                from: {alpha: 0},
                duration: 500,
                ease: 'sineIn'
            }
        );
    }
}

export default PhotoView;
